// TC22: valid intelligence sword no talisman - { characterLevel:10, buildType:"intelligence", weaponType:"sword", includeTalismans:false } → total:70

const calculator = {
  WEAPON_BASE: {
    sword: 50,
    axe: 70,
    staff: 40,
    bow: 55,
  },
  SCALING: {
    strength: { sword: 1.2, axe: 1.5, staff: 0.8, bow: 0.9 },
    dexterity: { sword: 1.0, axe: 0.9, staff: 0.7, bow: 1.5 },
    intelligence: { sword: 0.8, axe: 0.7, staff: 1.6, bow: 0.9 },
    faith: { sword: 1.1, axe: 1.0, staff: 1.2, bow: 0.8 },
  },
  validate(inputs) {
    const errors = [];
    const raw = inputs || {};
    // characterLevel
    const level = raw.characterLevel;
    if (level === undefined || level === null) {
      errors.push('characterLevel is required');
    } else if (typeof level !== 'number' || isNaN(level)) {
      errors.push('characterLevel must be a number');
    } else if (level <= 0) {
      errors.push('characterLevel must be positive');
    }
    // buildType
    const buildType = String(raw.buildType || '').toLowerCase();
    const validBuilds = ['strength', 'dexterity', 'intelligence', 'faith'];
    if (!validBuilds.includes(buildType)) {
      errors.push('Invalid build type');
    }
    // weaponType
    const weaponType = String(raw.weaponType || '').toLowerCase();
    const validWeapons = ['sword', 'axe', 'staff', 'bow'];
    if (!validWeapons.includes(weaponType)) {
      errors.push('Invalid weapon type');
    }
    // includeTalismans
    const talismans = raw.includeTalismans;
    if (typeof talismans !== 'boolean') {
      errors.push('includeTalismans must be a boolean');
    }
    return {
      errors,
      normalized: errors.length === 0 ? {
        characterLevel: level,
        buildType,
        weaponType,
        includeTalismans: talismans,
      } : {},
    };
  },
  calculate(inputs) {
    const { errors, normalized } = this.validate(inputs);
    if (errors.length > 0) {
      return { error: errors.join(', ') };
    }
    const { characterLevel, buildType, weaponType, includeTalismans } = normalized;
    const weaponBase = this.WEAPON_BASE[weaponType];
    const scalingFactor = this.SCALING[buildType][weaponType];
    const baseDamage = weaponBase * scalingFactor;
    const levelBonus = characterLevel * 3;
    const subtotal = baseDamage + levelBonus;
    const talismanMultiplier = includeTalismans ? 1.2 : 1.0;
    const total = subtotal * talismanMultiplier;
    // Round to two decimals
    const round2 = (n) => Math.round(n * 100) / 100;
    return {
      total: round2(total),
      breakdown: {
        weaponBase,
        scalingFactor,
        baseDamage: round2(baseDamage),
        levelBonus,
        talismanMultiplier,
        subtotal: round2(subtotal),
      },
    };
  },
  formatCurrency(amount) {
    return '$' + amount.toFixed(2);
  },
};

const CALC_PARAMS = [
  {
    name: 'characterLevel',
    label: 'Character Level',
    type: 'number',
    placeholder: 'e.g. 50',
  },
  {
    name: 'buildType',
    label: 'Build Type',
    type: 'select',
    options: [
      ['strength', '💪 Strength'],
      ['dexterity', '🏹 Dexterity'],
      ['intelligence', '📚 Intelligence'],
      ['faith', '✝️ Faith'],
    ],
  },
  {
    name: 'weaponType',
    label: 'Weapon Type',
    type: 'select',
    options: [
      ['sword', '🗡️ Sword'],
      ['axe', '🪓 Axe'],
      ['staff', '🪄 Staff'],
      ['bow', '🏹 Bow'],
    ],
  },
  {
    name: 'includeTalismans',
    label: 'Include Talismans?',
    type: 'checkbox',
  },
];
